// ---------- Inputs ----------
/**
 * Expects a Telegram update upstream.
 * - Image is in binary (first binary key)
 * - Caption (optional) at $.message.caption or $.caption
 * - Optional "insights" (tone/length hints) at $.insights
 * Provide your uploaded resume file_id below.
 */
const inputItem = $('Telegram Trigger').first();

// Detect first binary (photo)
const firstBinaryKey = Object.keys(inputItem.binary || {})[0];
if (!firstBinaryKey) {
  throw new Error("No binary image found in input. Connect the job post image.");
}
const jobImageBinary = inputItem.binary[firstBinaryKey].data;
const jobImageMime   = inputItem.binary[firstBinaryKey].mimeType || "image/jpeg";
const jobImageBase64 = `data:${jobImageMime};base64,${jobImageBinary}`;

// Telegram caption (pass through verbatim; do NOT parse or regex)
const caption =
  inputItem.json?.message?.caption ??
  inputItem.json?.caption ??
  "";

// Optional extra guidance from upstream
const insights = (inputItem.json?.insights ?? "").toString();

// ---------- Config ----------
const MODEL = "gpt-5.2";
const resumeFileId = "YOUR_OPENAI_FILE_ID_HERE"; // <-- replace with your own file_id
if (!resumeFileId?.startsWith("file-")) {
  throw new Error("Invalid resume file_id. Upload your resume to OpenAI and update the constant.");
}

// ---------- Prompts ----------
const systemPrompt = `
You are a job-application assistant.

Only pick ONE job offer to process — the one most clearly related to Data roles
(Data Engineer, Data Analyst, Data Scientist, ML/AI, Analytics, BI, etc.) and best matching the attached resume.

Priority of sources:
P1) CAPTION (if provided) — treat as highest-priority instructions/hints.
    If CAPTION says to use a particular email (e.g., "send to this email ..."),
    use that email for recruiter_email even if the image shows a different one.
P2) Job post IMAGE content.
P3) Resume.

Tasks:
1) Read the job post IMAGE and extract fields into the provided JSON schema.
2) Use the CAPTION (P1) to override/guide decisions, including recruiter_email selection.
3) Read the resume and identify:
   - The most relevant past experiences,
   - Concrete achievements,
   - Technical skills and tools,
   - Business impact that aligns with the job post.
4) Using those findings, draft a concise, professional outreach email tailored to the role.
   - Explicitly highlight a few resume-backed experiences that match the job post.
   - Integrate them naturally (no lists, no bullet points).
   - Refine the language for clarity, professionalism, and human tone.
5) Detect the job language and write the email in that language (FR post → FR email; else EN).

Output rules:
- Be concise, warm, confident (no buzzwords, no generic AI clichés).
- Only claim skills and experiences supported by the resume.
- If a field is missing, return "" for strings or [] for arrays (no hallucination).
- Email body: ~120–180 words unless INSIGHTS specify otherwise.
- Emphasize relevance: relate my previous work directly to the job responsibilities.
- Subject: ~6–10 words.
- Plain text only (no markdown).
`;

const userPrompt = `
From the job image:
- Extract all fields exactly as defined in the schema.
- Recruiter email selection order:
  1) Anything instructed in CAPTION (highest priority).
  2) Otherwise use the recruiter/application email from the IMAGE.
  3) Otherwise set recruiter_email to "".

Then, using my resume:
- Identify my most relevant past experiences and skills that match this role.
- Incorporate those experiences naturally into the outreach email to show clear alignment.
- Highlight achievements only if they appear in the resume.
- Refine the email for clarity, flow, and professionalism.
- Follow INSIGHTS (tone/length). If CAPTION and INSIGHTS conflict, CAPTION wins.

Return ONLY the JSON according to the schema (no extra text).
`;

// ---------- Build /v1/responses payload ----------
const payload = {
  model: MODEL,
  input: [
    {
      role: "system",
      content: [{ type: "input_text", text: systemPrompt.trim() }]
    },
    {
      role: "user",
      content: [
        { type: "input_text", text: userPrompt.trim() },

        // Provide CAPTION and INSIGHTS verbatim (no parsing)
        { type: "input_text", text: `CAPTION (P1): ${caption || "(none)"}` },
        { type: "input_text", text: `INSIGHTS: ${insights || "(none)"}` },

        // Image to parse
        { type: "input_image", image_url: jobImageBase64 },

        // Resume file reference
        { type: "input_file", file_id: resumeFileId }
      ]
    }
  ],
  text: {
    format: {
      type: "json_schema",
      name: "job_apply_payload_v1",
      strict: true,
      schema: {
        type: "object",
        additionalProperties: false,
        properties: {
          job_fields: {
            type: "object",
            additionalProperties: false,
            properties: {
              title:            { type: "string" },
              company:          { type: "string" },
              location:         { type: "string" },
              seniority:        { type: "string" },
              employment_type:  { type: "string" },
              language:         { type: "string" },
              requirements:     { type: "array", items: { type: "string" } },
              nice_to_have:     { type: "array", items: { type: "string" } },
              salary_range:     { type: "string" },
              posted_date:      { type: "string" },
              recruiter_email:  { type: "string" }
            },
            required: [
              "title",
              "company",
              "location",
              "seniority",
              "employment_type",
              "language",
              "requirements",
              "nice_to_have",
              "salary_range",
              "posted_date",
              "recruiter_email"
            ]
          },
          email_subject: { type: "string" },
          email_body:    { type: "string" }
        },
        required: ["job_fields", "email_subject", "email_body"]
      }
    }
  },
  max_output_tokens: 1000
};

return { json: { payload } };

const raw = $json.output?.[0]?.content?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(raw); }
catch (e) { throw new Error("Failed to parse model JSON: " + e.message + "\nRaw: " + raw); }
return { json: parsed };
// -> json.job_fields.*, json.email_subject, json.email_body

